33	enum class AttentionType {
34	    UNFUSED_MHA,
35	    UNFUSED_PADDED_MHA,
36	    FUSED_MHA,
37	    FUSED_PADDED_MHA
38	};
39	
40	/* NOTE:
41	1. only swin-style relative position bias is supported currently
42	2. gpt-style (causal-mask) models support any-sequence-length fmha, so we don't need to call isValidSeqLen at run-time
43	3. bert/vit can also support any-seq-length fmha
44	*/
45	template<typename T>
46	AttentionType getAttentionType(size_t     size_per_head,
47	                               const int  sm,
48	                               const bool remove_padding,
49	                               const int  max_seq_len,
50	                               const bool is_fuse                          = true,
51	                               const bool with_swin_relative_position_bias = false,
52	                               const bool causal_mask                      = false)
53	{
54	
55	    if (std::is_same<T, half>::value && is_fuse) {
56	        // Bert/Vit
57	        if (!causal_mask) {
58	            if (!with_swin_relative_position_bias
59	                && (((sm == kSM_70 || sm == kSM_72) && size_per_head == 64)
60	                    || ((sm == kSM_75 || sm == kSM_80 || sm == kSM_86)
61	                        && (size_per_head == 64 || size_per_head == 32)))) {
62	                return remove_padding ? AttentionType::FUSED_MHA : AttentionType::FUSED_PADDED_MHA;
63	            }
64	            else if (with_swin_relative_position_bias && (sm == kSM_75 || sm == kSM_80 || sm == kSM_86)
65	                     && max_seq_len <= 256 && size_per_head == 32) {
66	                return remove_padding ? AttentionType::FUSED_MHA : AttentionType::FUSED_PADDED_MHA;
67	            }
68	        }
69	        // GPT and its variants
70	        else {
71	           // FMHA_ENABLE only affects gpt-style models (causal-mask)
72	            char * fused_qkv = std::getenv("FMHA_ENABLE");
73	            if (fused_qkv != nullptr && std::string(fused_qkv) == "ON") {
74	                if ((sm == kSM_70 || sm == kSM_72 || sm == kSM_75 || sm == kSM_80 || sm == kSM_86 || sm == kSM_89)
75	                    && (size_per_head == 32 || size_per_head == 40 || size_per_head == 64 || size_per_head == 80
76	                        || size_per_head == 128 || size_per_head == 144 || size_per_head == 160 || size_per_head == 256)) {
77	                    return remove_padding ? AttentionType::FUSED_MHA : AttentionType::UNFUSED_PADDED_MHA;
78	                }
79	            }
80	        }
81	    }
82	#ifdef ENABLE_FP8
83	    else if (std::is_same<T, __nv_fp8_e4m3>::value && is_fuse) {
84	        if (!causal_mask) {
85	            if ((sm == kSM_89 || sm == kSM_90) && max_seq_len < 512 && is_fuse && size_per_head == 64) {
86	                return remove_padding ? AttentionType::FUSED_MHA : AttentionType::FUSED_PADDED_MHA;
87	            }
88	            else {
89	                return remove_padding ? AttentionType::UNFUSED_MHA : AttentionType::UNFUSED_PADDED_MHA;
90	            }
91	        }
92	    }
93	#endif
94	
95	    return remove_padding ? AttentionType::UNFUSED_MHA : AttentionType::UNFUSED_PADDED_MHA;
96	}
97	
98	template<typename T>
99	AttentionType getAttentionTypeINT8(
100	    size_t size_per_head, const int sm, const bool remove_padding, const int max_seq_len, const int int8_mode)
101	{
102	    if ((int8_mode == 1 || int8_mode == 2)
103	        && (((sm == kSM_80 || sm == kSM_86) && (size_per_head == 64 || size_per_head == 32) && max_seq_len <= 512)
104	            || (sm == kSM_75
105	                && ((size_per_head == 64 && max_seq_len <= 384) || (size_per_head == 32 && max_seq_len <= 512))))) {
106	        return remove_padding ? AttentionType::FUSED_MHA : AttentionType::FUSED_PADDED_MHA;
107	    }
108	    else {
109	        return remove_padding ? AttentionType::UNFUSED_MHA : AttentionType::UNFUSED_PADDED_MHA;
110	    }
111	}
