20	
21	__global__ void trt_add_QKV_bias(half2*       qkv_buf,
22	                                 const half2* Q,
23	                                 const half2* bias_Q,
24	                                 const half2* K,
25	                                 const half2* bias_K,
26	                                 const half2* V,
27	                                 const half2* bias_V,
28	                                 const int    valid_word_num,
29	                                 const int    head_num,
30	                                 const int    size_per_head)
31	{
32	    // Add bias, and then transpose from
33	    // [3, valid_word_num, head, size] -> [valid_word_num, head, 3, size]
34	
35	    // const int seq_id = blockIdx.x % valid_word_num;
36	    // const int qkv_id = (blockIdx.x - seq_id) / valid_word_num;
37	    const int seq_id = blockIdx.x;
38	
39	    for (int index = threadIdx.x; index < head_num * size_per_head; index += blockDim.x) {
40	        const int size_id = index % size_per_head;
41	        const int head_id = (index - size_id) / size_per_head;
42	
43	        const int target_offset = blockIdx.x * head_num * 3 * size_per_head + head_id * 3 * size_per_head;
44	        const int src_id        = seq_id * head_num * size_per_head + index;
45	
46	        qkv_buf[target_offset + 0 * size_per_head + size_id] = Q[src_id] + bias_Q[index];
47	        qkv_buf[target_offset + 1 * size_per_head + size_id] = K[src_id] + bias_K[index];
48	        qkv_buf[target_offset + 2 * size_per_head + size_id] = V[src_id] + bias_V[index];
49	    }
50	}
51	
52	template<typename T>
53	void FusedAttentionLayer<T>::invokeTrtAddQkvBias(size_t token_num, const AttentionWeight<T>* attention_weights)
54	{
55	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
56	    dim3 grid(token_num);
57	    dim3 block(min((int)(head_num_ * size_per_head_ / 2), 512));
58	
59	    trt_add_QKV_bias<<<grid, block, 0, stream_>>>((half2*)qkv_buf_,
60	                                                  (const half2*)q_buf_,
61	                                                  (const half2*)attention_weights->query_weight.bias,
62	                                                  (const half2*)k_buf_,
63	                                                  (const half2*)attention_weights->key_weight.bias,
64	                                                  (const half2*)v_buf_,
65	                                                  (const half2*)attention_weights->value_weight.bias,
66	                                                  token_num,
67	                                                  head_num_,
68	                                                  size_per_head_ / 2);
69	}
70	
71	template<typename T>
72	void FusedAttentionLayer<T>::forward(TensorMap*                output_tensors,
73	                                     TensorMap*                input_tensors,
74	                                     const AttentionWeight<T>* attention_weights)
75	{
76	    // input_tensors: [input_query (h_token_num, d_model),
77	    //                 attention_mask (batch, 1, seqlen, seqlen),
78	    //                 padding_offset (batch + 1 or batch * 2 + 1))]
79	    // If padding_offset.data is nullptr, then not remove padding
80	
81	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
82	
83	    const int request_batch_size = input_tensors->at("attention_mask").shape[0];
84	    const int request_seq_len    = input_tensors->at("attention_mask").shape[2];
85	    allocateBuffer(request_batch_size, request_seq_len);
86	
87	    T*         attention_out  = output_tensors->getPtr<T>("hidden_features");
88	    const T*   from_tensor    = input_tensors->getPtr<T>("input_query");
89	    const T*   attention_mask = input_tensors->getPtr<T>("attention_mask");
90	    const int* padding_offset = input_tensors->getPtr<int>("padding_offset");
91	
92	    size_t m_tmp = input_tensors->at("input_query").shape[0];
93	    if (m_tmp % 8 != 0) {
94	        m_tmp = (m_tmp / 8 + 1) * 8;
95	    }
96	    const size_t m = input_tensors->at("input_query").shape[0];
97	    int          k = d_model_;
98	    int          n = hidden_units_;
99	
100	#ifdef SPARSITY_ENABLED
101	    const size_t m_padded = m_tmp;
102	    if (sparse_ && cublas_wrapper_->isUseSparse(1, n, m, k)) {
103	        cublas_wrapper_->SpGemm(
104	            CUBLAS_OP_N, CUBLAS_OP_N, n, m_padded, k, attention_weights->query_weight.sp_kernel, from_tensor, q_buf_);
105	        cublas_wrapper_->SpGemm(
106	            CUBLAS_OP_N, CUBLAS_OP_N, n, m_padded, k, attention_weights->key_weight.sp_kernel, from_tensor, k_buf_);
107	        cublas_wrapper_->SpGemm(
108	            CUBLAS_OP_N, CUBLAS_OP_N, n, m_padded, k, attention_weights->value_weight.sp_kernel, from_tensor, v_buf_);
109	    }
110	    else {
111	#endif
112	        const bool is_batched_QKV_ = cublas_wrapper_->isFuseBatchGemm(3, n, m, k);
113	        if (is_batched_QKV_) {
114	            const T* hA[]{attention_weights->query_weight.kernel,
115	                          attention_weights->key_weight.kernel,
116	                          attention_weights->value_weight.kernel,
117	                          nullptr,
118	                          from_tensor,
119	                          from_tensor,
120	                          from_tensor,
121	                          nullptr,
122	                          q_buf_,
123	                          k_buf_,
124	                          v_buf_,
125	                          nullptr};
126	            // Note: Here, we assume the weights of each time may be different.
127	            // If we can preprocess these weights before inference, we can reduce the overhead
128	            // caused by cudaMemcpyAsync
129	            check_cuda_error(
130	                cudaMemcpyAsync((void*)batch_qkv_kernel_ptr_, hA, sizeof(T*) * 12, cudaMemcpyHostToDevice, stream_));
131	            cublas_wrapper_->batchedGemm(CUBLAS_OP_N,
132	                                         CUBLAS_OP_N,
133	                                         n,
134	                                         m,
135	                                         k,
136	                                         (const void* const*)batch_qkv_kernel_ptr_,
137	                                         n,
138	                                         (const void* const*)batch_qkv_input_ptr_,
139	                                         k,
140	                                         (void* const*)batch_qkv_buf_ptr_,
141	                                         n,
142	                                         3);
143	        }
144	        else {
145	            cublas_wrapper_->Gemm(CUBLAS_OP_N,
146	                                  CUBLAS_OP_N,
147	                                  n,
148	                                  m,
149	                                  k,
150	                                  attention_weights->query_weight.kernel,
151	                                  n,
152	                                  from_tensor,
153	                                  k,
154	                                  q_buf_,
155	                                  n);
156	            cublas_wrapper_->Gemm(
157	                CUBLAS_OP_N, CUBLAS_OP_N, n, m, k, attention_weights->key_weight.kernel, n, from_tensor, k, k_buf_, n);
158	            cublas_wrapper_->Gemm(CUBLAS_OP_N,
159	                                  CUBLAS_OP_N,
160	                                  n,
161	                                  m,
162	                                  k,
163	                                  attention_weights->value_weight.kernel,
164	                                  n,
165	                                  from_tensor,
166	                                  k,
167	                                  v_buf_,
168	                                  n);
169	        }
170	#ifdef SPARSITY_ENABLED
171	    }
172	#endif
173	
174	    invokeTrtAddQkvBias(m, attention_weights);
175	    sync_check_cuda_error();
176	
177	    int S = dispatcher_fp16->getSFromMaxSeqLen(request_seq_len);
178	    FT_CHECK(dispatcher_fp16->isValid(S, false));
179	    const int B = input_tensors->at("padding_offset").shape[0] - 1;
180	    dispatcher_fp16->setup(S, B);
181	    dispatcher_fp16->run(qkv_buf_, nullptr, padding_offset, attn_workspace_, qkv_buf_2_, stream_);
182	    sync_check_cuda_error();
183	
184	    k = hidden_units_;
185	    n = d_model_;
186	#ifdef SPARSITY_ENABLED
187	    if (sparse_ && cublas_wrapper_->isUseSparse(1, n, m, k)) {
188	        cublas_wrapper_->SpGemm(CUBLAS_OP_N,
189	                                CUBLAS_OP_N,
190	                                n,
191	                                m_padded,
192	                                k,
193	                                attention_weights->attention_output_weight.sp_kernel,
194	                                qkv_buf_2_,
195	                                attention_out);
196	    }
197	    else {
198	#endif
199	        cublas_wrapper_->Gemm(CUBLAS_OP_N,
200	                              CUBLAS_OP_N,
201	                              n,
202	                              m,
203	                              k,
204	                              attention_weights->attention_output_weight.kernel,
205	                              n,
206	                              qkv_buf_2_,
207	                              k,
208	                              attention_out,
209	                              n);
210	#ifdef SPARSITY_ENABLED
211	    }
212	#endif
213	
214	    if (is_free_buffer_after_forward_ == true) {
215	        freeBuffer();
216	    }
217	}
